# Expense Tracker - Built with Python OOP# Features: add expenses, view expenses, get total, savings goal trackingimport sqlite3class ExpenseTracker:    def __init__(self):        self.connection = sqlite3.connect("learning_python.db")        self.cursor = self.connection.cursor()        self.cursor.execute("""        CREATE TABLE IF NOT EXISTS expenses(          id INTEGER PRIMARY KEY AUTOINCREMENT,          name TEXT NOT NULL,          amount REAL NOT NULL          )        """)        self.connection.commit()        print("Database ready")    def update_expenses(self,new_amount,expense_id):        self.cursor.execute("""        UPDATE expenses        SET amount = ?        WHERE id = ?    """,(new_amount,expense_id))        if self.cursor.rowcount == 0:            print("No expenses found!")        else:            self.connection.commit()            print("Expense updated successfully!")    def delete_expenses(self,expense_id):        self.cursor.execute("""        DELETE FROM expenses         WHERE id = ?    """,(expense_id,))        if self.cursor.rowcount == 0:            print("No expenses found")        else:            self.connection.commit()            print("Expenses deleted successfully!")    def add_expense(self):        expense_name = input("Enter expense name: ")        while True:            try:                expense_amount = float(input("Enter expense amount: "))                break            except ValueError:                print("please enter a valid number")        self.cursor.execute("""             INSERT INTO expenses (name, amount)             VALUES (?, ?)        """, (expense_name, expense_amount))        self.connection.commit()        print(f"{expense_name} added successfully")    def view_expenses(self):        self.cursor.execute("SELECT * FROM expenses")        expenses = self.cursor.fetchall()        if len(expenses) == 0:            print("No expenses found!")        else:            for expense in expenses:                print(f"ID: {expense[0]} | Name: {expense[1]} | Amount: {expense[2]}")    def get_total(self):        self.cursor.execute("SELECT SUM(amount) FROM expenses")        result = self.cursor.fetchone()        total = result[0] if result[0] is not None else 0        return totalclass SavingsTracker(ExpenseTracker):    def __init__(self,savings_goal):        super().__init__()        self.savings_goal = savings_goal    def check_goal(self):        total_spent = self.get_total()        remaining = self.savings_goal - total_spent        if remaining > 0:            print(f"You need {remaining} to reach your goal")        else:            print("You have reached your goal")if __name__ == "__main__":  while True:    try:        user_input = int(input("Choose tracker 1 or tracker 2: "))        break    except ValueError:        print("Invalid number , please try again")  if user_input == 1:    tracker = ExpenseTracker()  else:       while True:             try:              goal = float(input("Enter your savings goal: R"))              tracker = SavingsTracker(goal)              break             except ValueError:                print("Invalid number , please try again")  if user_input == 1:      while True:        print("1.Add expense")        print("2.View expense")        print("3.Get total")        print("4.Update expenses")        print("5.Delete expenses")        print("6.Quit")        while True:            try:             menu_option = int(input("Please select a menu option: "))             break            except ValueError:                print("Invalid number, please try again")        if menu_option == 1:            tracker.add_expense()        elif menu_option == 2:            tracker.view_expenses()        elif menu_option == 3:            print(f"total expenses: R{tracker.get_total()}")        elif menu_option == 4:            tracker.view_expenses()            while True:                try:                 new_amount = float(input("Enter new amount: "))                 break                except ValueError:                    print("Invalid number,please try agan")            while True:                try:                    expense_id = int(input("Enter id: "))                    break                except ValueError:                    print("Invalid number , please try again")            tracker.update_expenses(new_amount,expense_id)        elif menu_option == 5:            while True:                tracker.view_expenses()                try:                    expense_id = int(input("Enter id: "))                    break                except ValueError:                    print("Invalid number, please try again")            tracker.delete_expenses(expense_id)        elif menu_option == 6:            print("Goodbye!")            break  else:      while True:          print("1.Add expense")          print("2.View expense")          print("3.Get total")          print("4.Check savings goal")          print("5.Quit")          while True:              try:                  menu_option =int(input("Enter menu option: "))                  break              except ValueError:                  print("Invalid number, please try again")          if menu_option == 1:            tracker.add_expense()          elif menu_option == 2:              tracker.view_expenses()          elif menu_option == 3:              print(f"Your total is R{tracker.get_total()}")          elif menu_option == 4:              tracker.check_goal()          elif menu_option == 5:              print("Goodbye!")              break